def untar_file(path, fn):
    """Extracts a tar archive.

    Args:
        path (str): the path to where the file will be extracted
        fn (str): the name of the tar archive

    """
    try:
        check_call(['tar', '-C', path, '-xf', fn])
    except CalledProcessError:
        raise GenipeError('Could not extract {}'.format(fn))

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Return the number of matches for the selected database and
    parameters.

    Keyword Arguments:
        db        -- LIPID MAPS' database
        mzStr     -- string with one m/z per line (text file alike)
        adducts   -- list of adducts separated by commas
        tolerance -- mass tolerance in Daltons (+/- to each m/z)
                     [default: 0.001]
    """
    mpData = MultipartEncoder(fields={'CHOICE': db, 'ion': adducts, 'file':
        ('file', StringIO(mzStr), 'text/plain'), 'tol': str(tolerance),
        'sort': 'DELTA'})
    try:
        response = requests.post(LIPIDMAPS_URL, data=mpData, headers={
            'Content-Type': mpData.content_type})
    except:
        raise Exception(
            'Connection error with the database. Please check your network and try again after a few minutes.'
            )
    if len(response.text) == 0:
        return 0
    else:
        matches = pandas.read_csv(StringIO(response.text), sep='\t', engine
            ='python', index_col=False)
        if matches.empty:
            return 0
        else:
            return len(matches['Input Mass'].unique())

